	dot(P);
	P = intersectionpoints(Circle((2*i + 1)/2,1/2),(-2.8,-2.8/5)--(2.8,2.8/5))[1];
	dot(P);
}

draw((-2.8,-2.8/5)--(2.8,2.8/5));
