dot("$(-\frac{5}{2},0)$", (-5/2,0), S);
dot("$(-\frac{3}{2},0)$", (-3/2,0), S);
dot("$(-\frac{1}{2},0)$", (-1/2,0), S);
dot("$(\frac{1}{2},0)$", (1/2,0), S);
dot("$(\frac{3}{2},0)$", (3/2,0), S);
dot("$(\frac{5}{2},0)$", (5/2,0), S);
dot("$(\frac{5}{2},\frac{1}{2})$", (5/2,1/2), N);
